('web-001', 'Port Scan Detection', 'web', 'easy', 100, 'Detect scanning patterns.', '+ICX6sYQN+fHhX5Y8+aoGEErYxwKA0qKrLs6UVpsdic=', '[{"briefing":"Identify the scanner behavior in the access logs.","flagHash":"+ICX6sYQN+fHhX5Y8+aoGEErYxwKA0qKrLs6UVpsdic=","learningContent":"Port scans create repeated connection attempts across services or paths."}]', '[{"content":"Look for repeated probes from the same source."},{"content":"Group activity by source and requested service."},{"content":"The flag references the scan pattern."}]', 'Port scanning detection starts by grouping noisy connection attempts into a single actor pattern.', NOW()),
('web-002', 'SQL Injection', 'web', 'medium', 200, 'Exploit login form.', 'fMEUYrgckFBxrRVlCeYem7RR11177cpRMm9Jjlz685g=', '[{"briefing":"Find the unsafe login query behavior.","flagHash":"fMEUYrgckFBxrRVlCeYem7RR11177cpRMm9Jjlz685g=","learningContent":"SQL injection appears when user input changes query structure instead of data values."}]', '[{"content":"Try thinking about how a login WHERE clause is built."},{"content":"Authentication bypass often targets boolean logic."},{"content":"The flag names the injection technique."}]', 'Parameterized queries prevent user input from becoming executable SQL.', NOW()),
('web-003', 'XSS Challenge', 'web', 'hard', 300, 'Bypass filter.', 'tsoMLY4HvyC/IAOgAjZJ5/P7QrYmO29hqki9nc3/Gs4=', '[{"briefing":"Bypass the naive script filter safely.","flagHash":"tsoMLY4HvyC/IAOgAjZJ5/P7QrYmO29hqki9nc3/Gs4=","learningContent":"XSS defenses must encode by context, not only blacklist words."}]', '[{"content":"Blacklists miss alternate event and encoding paths."},{"content":"Think about HTML attribute contexts."},{"content":"The flag references bypassing an XSS filter."}]', 'Robust XSS defense uses output encoding, CSP, and sanitization matched to the rendering context.', NOW()),
